var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`사람 살려!`,JPN:`助けてくれ！`,ENG:`Help!!`,TWN:`救命！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`괴......괴물!`,JPN:`ば……化け物だ！`,ENG:`M-monster!`,TWN:`怪……怪物！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`도망쳐!`,JPN:`逃げろ！`,ENG:`Run away!`,TWN:`快逃啊！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`경비원은 뭘 하는 거야?`,JPN:`警備員は何をしてるんだ？`,ENG:`What’s the security guard doing?`,TWN:`警衛在幹什麼？`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`경찰을 불러!`,JPN:`警察を呼べ！`,ENG:`Call the cops!`,TWN:`快叫警察！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`DAUGHTER_EXTRA_NULL_GIRL`,text:{KOREA:`아빠. 이제 한계야.`,JPN:`パパ。私、もう限界。`,ENG:`Dad. It’s over.`,TWN:`爸爸，我已經到極限了。`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`DAUGHTER_EXTRA_NULL_GIRL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`EDDIE_RSEVEN_NULL_NULL`,text:{KOREA:`......아니야.`,JPN:`……そんなことない。`,ENG:`No...`,TWN:`……不。`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`EDDIE_RSEVEN_NULL_NULL`,text:{KOREA:`한 번만, 한 번만 더 버텨보자.`,JPN:`もう一度だけ、もう一度だけ頑張ろう。`,ENG:`Let’s give this one more try.`,TWN:`一次就好，再堅持一次吧。`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`DAUGHTER_EXTRA_NULL_GIRL`,text:{KOREA:`아빠도 알고 있잖아.`,JPN:`パパも気づいてるでしょ？`,ENG:`But you know it too, dad.`,TWN:`爸爸你其實也知道吧。`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`DAUGHTER_EXTRA_NULL_GIRL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`DAUGHTER_EXTRA_NULL_GIRL`,text:{KOREA:`난 이제 더 이상 버티지 못해.`,JPN:`私、もう耐えられないの。`,ENG:`This is it for me.`,TWN:`我現在已經撐不住了。`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`DAUGHTER_EXTRA_NULL_GIRL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`EDDIE_RSEVEN_NULL_NULL`,text:{KOREA:`아, 아니야......`,JPN:`ち、違う……`,ENG:`N-no...`,TWN:`不，不會的……`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`EDDIE_RSEVEN_NULL_NULL`,text:{KOREA:`그렇지 않아......`,JPN:`そんなはずない……`,ENG:`That’s not true...`,TWN:`不會那樣的……`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`DAUGHTER_EXTRA_NULL_GIRL`,text:{KOREA:`아빠는 할 만큼 했어.`,JPN:`パパは十分頑張ったよ。`,ENG:`You did all you could.`,TWN:`爸爸已經盡力了。`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`DAUGHTER_EXTRA_NULL_GIRL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`EDDIE_RSEVEN_NULL_NULL`,text:{KOREA:`아니야!`,JPN:`違う！`,ENG:`No!`,TWN:`不！`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`EDDIE_RSEVEN_NULL_NULL`,text:{KOREA:`할 만큼 하지 않았어. 아직 뭔가 남았을 거야!`,JPN:`十分じゃない。きっと、何か方法があるはずだ！`,ENG:`There’s still more I can do. There’s got to be a way!`,TWN:`不，我還沒有盡力，應該還有什麼辦法的！`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`EDDIE_RSEVEN_NULL_NULL`,text:{KOREA:`아직 해 볼 수 있는 게 있을 거야!`,JPN:`まだ何かできるはずだ！`,ENG:`There must be something we haven’t tried yet!`,TWN:`應該還有可以為妳做的事情！`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`DAUGHTER_EXTRA_NULL_GIRL`,text:{KOREA:`괜찮아. 이제 충분해.`,JPN:`ううん。もういいの。`,ENG:`It’s okay. You've done enough.`,TWN:`沒關係，已經夠了。`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`DAUGHTER_EXTRA_NULL_GIRL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`EDDIE_RSEVEN_NULL_NULL`,text:{KOREA:`충분할 리가 없잖아!`,JPN:`そんなわけないだろ！`,ENG:`It’s not enough!`,TWN:`這還不夠！`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`EDDIE_RSEVEN_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`DAUGHTER_EXTRA_NULL_GIRL`,text:{KOREA:`충분해.`,JPN:`もう十分だよ。`,ENG:`It is.`,TWN:`夠了。`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`DAUGHTER_EXTRA_NULL_GIRL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};